diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..eea1b868139c 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4594,6 +4594,31 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
       return ConstantInt::getFalse(Cond->getType());

     Value *X, *Y;
+
+    // (X && Y) ? true : Y --> Y (commuted 2 ways)
+    // The condition is a select that represents a logical AND.
+    // If X is false, the result is Y (from the false branch).
+    // If X is true, the condition becomes Y, so the result is Y ? true : Y = Y.
+    if (match(TrueVal, m_One())) {
+      // (X && Y) ? true : Y --> Y
+      if (match(Cond, m_Select(m_Value(X), m_Specific(FalseVal), m_ZeroInt())))
+        return FalseVal;
+      // (Y && X) ? true : Y --> Y (commuted)
+      if (match(Cond, m_Select(m_Specific(FalseVal), m_Value(X), m_ZeroInt())))
+        return FalseVal;
+      // (X && Y) ? true : X --> X (FalseVal is X)
+      if (match(Cond, m_Select(m_Value(X), m_ZeroInt(), m_Specific(FalseVal))))
+        return FalseVal;
+      // (Y && X) ? true : X --> X (FalseVal is X, commuted)
+      if (match(Cond, m_Select(m_Specific(FalseVal), m_ZeroInt(), m_Value(X))))
+        return FalseVal;
+      // Y ? true : (X && Y) --> Y (absorption law)
+      if (match(FalseVal, m_Select(m_Value(X), m_Specific(Cond), m_ZeroInt())))
+        return Cond;
+      // Y ? true : (Y && X) --> Y (absorption law, commuted)
+      if (match(FalseVal, m_Select(m_Specific(Cond), m_Value(X), m_ZeroInt())))
+        return Cond;
+    }
     if (match(FalseVal, m_ZeroInt())) {
       // !(X || Y) && X --> false (commuted 2 ways)
       if (match(Cond, m_Not(m_c_LogicalOr(m_Specific(TrueVal), m_Value()))))
@@ -4610,9 +4635,6 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
   }

   // select ?, X, X -> X
-  if (TrueVal == FalseVal)
-    return TrueVal;
-
   if (Cond == TrueVal) {
     // select i1 X, i1 X, i1 false --> X (logical-and)
     if (match(FalseVal, m_ZeroInt()))

